const response = $input.first().json;
const executions = response.data || response.results || [];

if (!executions.length) {
  return [{ json: { hasNewErrors: false, errorCount: 0, errors: [] } }];
}

// Only errors in the last 5 minutes
const fiveMinAgo = new Date(Date.now() - 5 * 60 * 1000);

const recentErrors = executions.filter(exec => {
  const finishedAt = exec.stoppedAt || exec.startedAt;
  if (!finishedAt) return false;
  return new Date(finishedAt) >= fiveMinAgo;
});

if (!recentErrors.length) {
  return [{ json: { hasNewErrors: false, errorCount: 0, errors: [] } }];
}

const errors = recentErrors.map(exec => ({
  workflowName: exec.workflowData?.name || exec.workflowId || 'Unknown',
  errorMessage: exec.data?.resultData?.error?.message || exec.stoppedAt ? 'Execution failed' : 'Unknown error',
  timestamp: exec.stoppedAt || exec.startedAt,
  executionId: exec.id
}));

return [{ json: {
  hasNewErrors: true,
  errorCount: errors.length,
  errors
} }];
